// Helper: Leads aus actions-Array extrahieren
function getLeads(actions) {
  if (!actions) return 0;
  const lead = actions.find(a => a.action_type === 'lead' || a.action_type === 'offsite_conversion.fb_pixel_lead');
  return lead ? parseInt(lead.value) : 0;
}
function getCPL(costPerAction) {
  if (!costPerAction) return null;
  const lead = costPerAction.find(a => a.action_type === 'lead' || a.action_type === 'offsite_conversion.fb_pixel_lead');
  return lead ? parseFloat(lead.value) : null;
}

// ── Kampagnen (7 Tage) ──
const campaigns = ($('Meta: Kampagnen letzte 7 Tage').first().json.data || []);
const campSummaries = campaigns.map(c => {
  const leads = getLeads(c.actions);
  const cpl = getCPL(c.cost_per_action_type);
  const spend = parseFloat(c.spend || 0);
  return {
    name: c.campaign_name,
    spend,
    clicks: parseInt(c.clicks || 0),
    impressions: parseInt(c.impressions || 0),
    leads,
    cpl,
    ctr: parseFloat(c.ctr || 0)
  };
}).sort((a, b) => b.spend - a.spend);

const totalSpend7d = campSummaries.reduce((s, c) => s + c.spend, 0);
const totalLeads7d = campSummaries.reduce((s, c) => s + c.leads, 0);
const avgCPL7d = totalLeads7d > 0 ? (totalSpend7d / totalLeads7d).toFixed(2) : 'n/a';

// Top 3 Kampagnen
const topCamps = campSummaries.slice(0, 3).map(c => 
  `${c.name} (€${c.spend.toFixed(0)}, ${c.leads} Leads${c.cpl ? ', CPL: €' + c.cpl.toFixed(2) : ''})`
).join(' | ');

// Schlechteste CPL (wenn Leads > 0)
const worstCPL = campSummaries
  .filter(c => c.leads > 0 && c.cpl)
  .sort((a, b) => b.cpl - a.cpl)[0];

// ── Heute ──
const todayData = ($('Meta: Heute (Account-Level)').first().json.data || [])[0];
const todaySpend = todayData ? parseFloat(todayData.spend || 0) : 0;
const todayLeads = todayData ? getLeads(todayData.actions) : 0;
const todayClicks = todayData ? parseInt(todayData.clicks || 0) : 0;

// ── Dieser Monat ──
const monthData = ($('Meta: Dieser Monat').first().json.data || [])[0];
const monthSpend = monthData ? parseFloat(monthData.spend || 0) : 0;
const monthLeads = monthData ? getLeads(monthData.actions) : 0;

const monthCPL = monthLeads > 0 ? (monthSpend / monthLeads).toFixed(2) : 'n/a';

// ── Zusammenfassung ──
const today = new Date().toISOString().slice(0, 10);

const zusammenfassung = 
  `Heute: €${todaySpend.toFixed(0)} ausgegeben, ${todayLeads} Leads, ${todayClicks} Klicks. ` +
  `Letzte 7 Tage: €${totalSpend7d.toFixed(0)} Spend, ${totalLeads7d} Leads, Ø CPL: €${avgCPL7d}. ` +
  `Monat April: €${monthSpend.toFixed(0)} Spend, ${monthLeads} Leads, CPL: €${monthCPL}. ` +
  `Top-Kampagnen: ${topCamps || 'keine aktiven'}.` +
  (worstCPL ? ` ⚠️ Teuerste CPL: ${worstCPL.name} (€${worstCPL.cpl.toFixed(2)}).` : '');

return [{
  json: {
    id: 'kf-meta-' + today,
    pid: null,
    quelle: 'meta',
    typ: 'kampagnen',
    zusammenfassung,
    rohdaten: {
      today: { spend: todaySpend, leads: todayLeads, clicks: todayClicks },
      week: { spend: totalSpend7d, leads: totalLeads7d, cpl: avgCPL7d },
      month: { spend: monthSpend, leads: monthLeads, cpl: monthCPL },
      campaigns: campSummaries.slice(0, 5)
    },
    relevanz: 'hoch',
    created_at: new Date().toISOString(),
    gueltig_bis: today
  }
}];
